from elasticsearch import Elasticsearch

def execute_dynamic_script(es_host, req):
    # Initialize Elasticsearch client
    es = Elasticsearch([es_host])

    # Get script from user input
    script_code = req.get('script', '')

    if not script_code:
        return {"error": "Script code is required"}, 400

    # Prepare the aggregation with dynamic script
    aggregation_body = {
        "aggs": {
            "dynamic_script_agg": {
                "scripted_metric": {
                    "init_script": "_state.count = 0",
                    "map_script": script_code,
                    "combine_script": "_agg.count += _state.count",
                    "reduce_script": "total_count = 0; for agg in _aggs: total_count += agg.count; return total_count"
                }
            }
        }
    }

    # Execute the aggregation
    response = es.search(index="your_index", body=aggregation_body)

    return response

